css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f1f5f9; color: #1e293b; }
.page { display: flex; min-height: 100vh; max-width: 1100px; margin: 0 auto; background: white; box-shadow: 0 4px 32px rgba(0,0,0,0.08); }
.sidebar { width: 300px; background: #0f172a; color: white; padding: 40px 28px; flex-shrink: 0; }
.avatar { width: 80px; height: 80px; border-radius: 50%; background: linear-gradient(135deg, #22c55e, #16a34a); display: flex; align-items: center; justify-content: center; font-size: 28px; font-weight: 800; margin: 0 auto 16px; border: 3px solid rgba(34,197,94,0.4); }
.sidebar h1 { font-size: 22px; font-weight: 800; text-align: center; margin-bottom: 4px; }
.title { color: #22c55e; font-size: 13px; font-weight: 600; text-align: center; margin-bottom: 24px; }
.contact { border-top: 1px solid rgba(255,255,255,0.1); border-bottom: 1px solid rgba(255,255,255,0.1); padding: 16px 0; margin-bottom: 24px; }
.contact-item { font-size: 13px; color: rgba(255,255,255,0.7); padding: 6px 0; }
.section { margin-bottom: 24px; }
.section h3 { font-size: 13px; font-weight: 700; color: #22c55e; letter-spacing: 2px; margin-bottom: 14px; }
.skills { display: flex; flex-direction: column; gap: 10px; }
.skill span { font-size: 12px; color: rgba(255,255,255,0.8); display: block; margin-bottom: 4px; }
.skill-bar { height: 4px; background: rgba(255,255,255,0.1); border-radius: 2px; } .skill-bar div { height: 100%; border-radius: 2px; background: linear-gradient(90deg, #22c55e, #86efac); }
.langs { display: flex; flex-direction: column; gap: 8px; }
.lang-item { display: flex; justify-content: space-between; align-items: center; font-size: 13px; color: rgba(255,255,255,0.8); }
.lang-level { padding: 2px 8px; border-radius: 10px; font-size: 11px; font-weight: 700; } .native { background: rgba(34,197,94,0.2); color: #22c55e; } .fluent { background: rgba(59,130,246,0.2); color: #60a5fa; } .basic { background: rgba(255,255,255,0.1); color: rgba(255,255,255,0.5); }
.download-btn { width: 100%; height: 44px; border-radius: 12px; border: 1px solid rgba(34,197,94,0.4); background: rgba(34,197,94,0.1); color: #22c55e; font-weight: 700; cursor: pointer; font-size: 13px; margin-top: 8px; transition: all 0.2s; } .download-btn:hover { background: rgba(34,197,94,0.2); }
.content { flex: 1; padding: 40px; overflow-y: auto; }
.content .section { margin-bottom: 36px; }
.content h2 { font-size: 20px; font-weight: 800; color: #0f172a; margin-bottom: 16px; padding-bottom: 10px; border-bottom: 2px solid #22c55e; }
.content p { font-size: 15px; color: #475569; line-height: 1.75; }
.timeline { display: flex; flex-direction: column; gap: 0; position: relative; }
.tl-item { display: flex; gap: 16px; position: relative; padding-bottom: 28px; }
.tl-dot { width: 12px; height: 12px; border-radius: 50%; background: #22c55e; flex-shrink: 0; margin-top: 5px; position: relative; z-index: 1; } .tl-item::before { content: ''; position: absolute; left: 5px; top: 16px; bottom: 0; width: 2px; background: #e2e8f0; }
.tl-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px; }
.tl-header strong { font-size: 16px; font-weight: 700; } .tl-period { font-size: 13px; color: #22c55e; font-weight: 600; }
.tl-company { font-size: 14px; color: #64748b; margin-bottom: 10px; }
.tl-desc { padding-left: 16px; } .tl-desc li { font-size: 14px; color: #475569; line-height: 1.7; margin-bottom: 4px; }
.edu-item { padding: 16px; background: #f8fafc; border-radius: 12px; border-left: 3px solid #22c55e; } .edu-item strong { display: block; font-size: 15px; font-weight: 700; margin-bottom: 4px; } .edu-item span { font-size: 13px; color: #64748b; }
.certs { display: flex; flex-direction: column; gap: 8px; }
.cert-item { padding: 12px 16px; background: #f0fdf4; border-radius: 10px; border: 1px solid #bbf7d0; font-size: 14px; font-weight: 600; color: #15803d; }
